package com.chaobo.scm.supplier.interfaces.web;import com.chaobo.scm.common.api.*;import com.chaobo.scm.supplier.application.contract.SupplierContractApplicationService;import com.chaobo.scm.supplier.application.shared.CommandResult;import com.chaobo.scm.supplier.infrastructure.security.CommandContextFactory;import jakarta.servlet.http.*;import jakarta.validation.*;import jakarta.validation.constraints.*;import org.springframework.security.core.*;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/internal/supplier/v1/contracts") public class ContractApprovalOpenApiController {private final SupplierContractApplicationService service;private final CommandContextFactory contexts;public ContractApprovalOpenApiController(SupplierContractApplicationService service,CommandContextFactory contexts){this.service=service;this.contexts=contexts;}@PostMapping("/{id}/approval-result")public ApiResponse<CommandResult> result(@PathVariable long id,@Valid @RequestBody Approval body,HttpServletRequest request,Authentication auth){if(!"IAM".equals(request.getHeader("X-Source-System")))throw new com.chaobo.scm.common.error.BusinessException(com.chaobo.scm.common.error.ErrorCode.FORBIDDEN,"来源系统必须是IAM");var context=contexts.create(request,auth);var result=body.approved()?service.approve(id,body.version(),context):service.rejectApproval(id,body.version(),body.comment(),context);return ApiResponse.success(result,request.getHeader("X-Request-Id"),request.getHeader("X-Trace-Id"));}public record Approval(@PositiveOrZero int version,boolean approved,String comment){}}
